function poisson(l){let L=Math.exp(-l),k=0,p=1;do{k++;p*=Math.random();}while(p>L);return Math.min(k-1,7);}
const avg=a=>a.length?a.reduce((x,y)=>x+y,0)/a.length:65;
const clampA=(v,lo,hi)=>Math.max(lo,Math.min(hi,v));

// p = [name,posG,posE,age,rat, 12 attrs...]
function effOf(p,pos){
  // efectividad SIEMPRE en su posicion natural, luego el % exacto por jugar fuera de puesto
  const nat=p[2];
  const w=EFF_W[nat]||EFF_W.MC;
  let raw=0; for(let i=0;i<12;i++) raw+=p[5+i]*w[i];
  const scaled=Math.max(45,Math.min(99,(raw-7)/11*(nat==="POR"?44:40)+(nat==="POR"?51:52)));
  const pen=(OUT_POS[nat]||{})[pos] ?? 0.40;
  return Math.round(scaled*pen);
}
function natRating(p){return effOf(p,p[2]);}

// XI = array de {pos, idx} (11 slots)
function bestXI(t,fk,R,inj){
  const slots=FORMS[fk], P=R[t];
  const hurt=i=>inj&&(inj[t+"_"+i]||0)>0;
  const cands=[];
  slots.forEach((pos,si)=>P.forEach((p,pi)=>{if(!hurt(pi))cands.push({si,pi,eff:effOf(p,pos)});}));
  cands.sort((a,b)=>b.eff-a.eff);
  const xi=new Array(11).fill(null), usedP=new Set(), usedS=new Set();
  for(const c of cands){
    if(usedS.has(c.si)||usedP.has(c.pi))continue;
    xi[c.si]={pos:slots[c.si],idx:c.pi};
    usedS.add(c.si);usedP.add(c.pi);
    if(usedS.size===11)break;
  }
  for(let si=0;si<11;si++) if(!xi[si]){
    const free=P.map((_,i)=>i).find(i=>!usedP.has(i)&&!hurt(i));
    if(free!==undefined){xi[si]={pos:slots[si],idx:free};usedP.add(free);}
  }
  return xi.filter(Boolean);
}

const ATT_POS={EXD:1,EXI:1,MP:1,MCO:1,DC:1,SD:1,MC:0.5};
const DEF_POS={POR:1,DFC:1,LTD:1,LTI:1,CAD:1,MCD:1,MC:0.5};
function strengthOf(t,xi,R){
  let aS=0,aW=0,dS=0,dW=0;
  xi.forEach(e=>{
    const eff=effOf(R[t][e.idx],e.pos);
    const wa=ATT_POS[e.pos]||0, wd=DEF_POS[e.pos]||0;
    aS+=eff*wa;aW+=wa;dS+=eff*wd;dW+=wd;
  });
  return {att:aW?aS/aW:60, def:dW?dS/dW:60};
}
// ===== PUNTUACION DE PARTIDO (escala 1-10, estilo CM) =====
function bumpR(M,side,si,d){
  const r=side==="H"?M.ratH:M.ratA;
  if(r&&r[si]!==undefined)r[si]=Math.max(1,Math.min(9.9,r[si]+d));
}
function gkSlot(side,M){
  const xi=side==="H"?M.xiH:M.xiA;
  return xi.findIndex(e=>!e.off&&e.pos==="POR");
}
function weightedScorer(t,xi,R){
  const W={DC:5,SD:4.5,EXD:4,EXI:4,MP:3.5,MCO:3,MC:2,MCD:1,CAD:0.7,LTD:0.6,LTI:0.6,DFC:0.5,POR:0.05};
  const ws=xi.map(e=>(W[e.pos]||1)*(R[t][e.idx][8]/12));
  let r=Math.random()*ws.reduce((a,b)=>a+b,0);
  for(let i=0;i<xi.length;i++){r-=ws[i];if(r<=0)return R[t][xi[i].idx][0];}
  return R[t][xi[xi.length-1].idx][0];
}
function simScore(h,a,xiH,xiA,R){
  const sh=strengthOf(h,xiH,R), sa=strengthOf(a,xiA,R);
  const lh=Math.max(0.25,Math.min(3.8,1.42*Math.pow(sh.att/sa.def,3.1)));
  const la=Math.max(0.2,Math.min(3.5,1.08*Math.pow(sa.att/sh.def,3.1)));
  const hg=poisson(lh), ag=poisson(la);
  return {hg,ag,sH:Array.from({length:hg},()=>weightedScorer(h,xiH,R)),sA:Array.from({length:ag},()=>weightedScorer(a,xiA,R))};
}
function genFixtures(ids){
  const n=ids.length, rounds=[]; let a=[...Array(n-1).keys()].map(i=>i+1);
  for(let r=0;r<n-1;r++){
    const l=[0,...a], pairs=[];
    for(let i=0;i<n/2;i++){const x=l[i],y=l[n-1-i];pairs.push(r%2?[ids[x],ids[y]]:[ids[y],ids[x]]);}
    rounds.push(pairs); a.unshift(a.pop());
  }
  return rounds.concat(rounds.map(rd=>rd.map(([h,w])=>[w,h])));
}
const price=(r,a)=>{const f=a<=21?1.3:a<=25?1.15:a<=29?0.9:a<=32?0.6:0.35;return Math.max(2,Math.round(Math.pow(Math.max(2,r-62),2)*0.13*f));};

// ============ EVOLUCION (cada 10 fechas) ============
const PHYS=[0,1,2,11], MENT=[9,10];
function evolveAll(R,myIdx,xiMine,scorers){
  const news=[];
  const newR=R.map((squad,t)=>{
    const starters=new Set(
      t===myIdx ? xiMine.map(e=>e.idx)
      : squad.map((p,i)=>[natRating(p),i]).sort((a,b)=>b[0]-a[0]).slice(0,11).map(([,i])=>i)
    );
    return squad.map((p,i)=>{
      const np=[...p];
      const age=p[3], pf=starters.has(i)?1:0.45;
      const goals=scorers[p[0]+"|"+t]||0;
      for(let k=0;k<12;k++){
        if(p[1]!=="POR"&&k===7)continue;
        const isP=PHYS.includes(k), isM=MENT.includes(k);
        let pUp=0,pDn=0;
        if(age<=20){pUp=(isP?0.35:isM?0.25:0.5)*pf;}
        else if(age<=23){pUp=(isP?0.2:isM?0.2:0.35)*pf;}
        else if(age<=27){pUp=(isP?0.05:isM?0.15:0.12)*pf;}
        else if(age<=29){pDn=isP?0.1:0;pUp=isM?0.1:0;}
        else if(age<=32){pDn=isP?0.25:isM?0:0.05;pUp=isM?0.08:0;}
        else{pDn=isP?0.5:isM?0:0.12;pUp=(k===10?0.1:isM?0.05:0);}
        if(k===3&&goals>0&&Math.random()<Math.min(0.5,goals*0.08))pUp+=0.4;
        const r=Math.random();
        let d=0; if(r<pUp)d=1; else if(r<pUp+pDn)d=-1;
        if(d!==0){
          const nv=clampA(np[5+k]+d,1,20);
          if(nv!==np[5+k]){
            if(t===myIdx)news.push(p[0]+": "+ATTR_KEYS[k]+" "+np[5+k]+(d>0?" \u2191":" \u2193")+nv);
            np[5+k]=nv;
          }
        }
      }
      np[4]=natRating(np);
      return np;
    });
  });
  return {R:newR,news};
}
function ageAll(R){
  return R.map(squad=>squad.map(p=>{const np=[...p];np[3]=p[3]+1;np[4]=natRating(np);return np;}));
}

// ============ MOTOR DE PARTIDO EN VIVO v4 ============
const drainRate=p=>clampA(0.62-(p[16]-10)*0.025,0.2,0.8);
const effLive=(p,pos,fit)=>effOf(p,pos)*(0.72+0.28*fit/100);

function liveStrength(side,M){
  const xi=side==="H"?M.xiH:M.xiA, fit=side==="H"?M.fitH:M.fitA, t=side==="H"?M.h:M.a;
  let aS=0,aW=0,dS=0,dW=0,on=0;
  xi.forEach((e,si)=>{
    if(e.off)return; on++;
    const eff=effLive(M.R[t][e.idx],e.pos,fit[si]);
    const wa=ATT_POS[e.pos]||0, wd=DEF_POS[e.pos]||0;
    aS+=eff*wa;aW+=wa;dS+=eff*wd;dW+=wd;
  });
  const men=Math.pow(on/11,1.25);
  return {att:(aW?aS/aW:55)*men, def:(dW?dS/dW:55)*men, on};
}
function liveScorer(side,M){
  const xi=side==="H"?M.xiH:M.xiA, t=side==="H"?M.h:M.a;
  const W={DC:5,SD:4.5,EXD:4,EXI:4,MP:3.5,MCO:3,MC:2,MCD:1,CAD:0.7,LTD:0.6,LTI:0.6,DFC:0.5,POR:0.05};
  const act=xi.filter(e=>!e.off);
  const ws=act.map(e=>(W[e.pos]||1)*(M.R[t][e.idx][8]/12));
  let r=Math.random()*ws.reduce((a,b)=>a+b,0);
  for(let i=0;i<act.length;i++){r-=ws[i];if(r<=0)return M.R[t][act[i].idx][0];}
  return M.R[t][act[act.length-1].idx][0];
}
function pickVictim(side,M,byAgr){
  const xi=side==="H"?M.xiH:M.xiA, t=side==="H"?M.h:M.a;
  const act=xi.map((e,si)=>({e,si})).filter(x=>!x.e.off);
  if(!act.length)return null;
  if(!byAgr)return act[Math.floor(Math.random()*act.length)];
  const ws=act.map(x=>M.R[t][x.e.idx][13]);
  let r=Math.random()*ws.reduce((a,b)=>a+b,0);
  for(let i=0;i<act.length;i++){r-=ws[i];if(r<=0)return act[i];}
  return act[act.length-1];
}
function aiAutoSub(side,M,slotIdx){
  const xi=side==="H"?M.xiH:M.xiA, bench=side==="H"?M.benchH:M.benchA;
  const fit=side==="H"?M.fitH:M.fitA, t=side==="H"?M.h:M.a;
  const subsKey=side==="H"?"subsH":"subsA";
  if(M[subsKey]<=0||!bench.length)return false;
  const slot=xi[slotIdx];
  let best=-1,bEff=-1;
  bench.forEach((pi,bi)=>{const ef=effOf(M.R[t][pi],slot.pos);if(ef>bEff){bEff=ef;best=bi;}});
  const inP=bench[best];
  M.log.push(M.minute+"' "+LT[LANG].sub(ALL[t].s,M.R[t][slot.idx][0],M.R[t][inP][0]));
  bench.splice(best,1);
  xi[slotIdx]={pos:slot.pos,idx:inP};
  fit[slotIdx]=100;
  if(M.ratH)(side==="H"?M.ratH:M.ratA)[slotIdx]=6;
  M[subsKey]--;
  return true;
}

// Un minuto de partido. auto=true: resolver lesiones del usuario automaticamente (modo instantaneo)
function stepMinute(M,myIdx,auto){
  if(M.done)return M;
  M.minute++;
  const m=M.minute;
  // drenaje fisico
  ["H","A"].forEach(side=>{
    const xi=side==="H"?M.xiH:M.xiA, fit=side==="H"?M.fitH:M.fitA, t=side==="H"?M.h:M.a;
    xi.forEach((e,si)=>{if(!e.off)fit[si]=Math.max(0,fit[si]-drainRate(M.R[t][e.idx]));});
  });
  const sH=liveStrength("H",M), sA=liveStrength("A",M);
  if(M.ratH&&m%5===0&&m>0){
    [["H",1],["A",-1]].forEach(([side,sg])=>{
      const xi=side==="H"?M.xiH:M.xiA, fit=side==="H"?M.fitH:M.fitA, t=side==="H"?M.h:M.a;
      const dom=sg*(M.pos-50)/100*0.1;
      xi.forEach((e,si)=>{
        if(e.off)return;
        const q=(effLive(M.R[t][e.idx],e.pos,fit[si])-74)/300;
        bumpR(M,side,si,(Math.random()-0.5)*0.22+dom+q*0.18);
      });
    });
  }
  // posesion
  const target=clampA(50+(sH.att+sH.def-sA.att-sA.def)*0.55,25,75);
  M.pos=clampA(M.pos+(target-M.pos)*0.06+(Math.random()-0.5)*2.4,18,82);
  // eventos de ataque
  [["H",sH,sA,0],["A",sA,sH,1]].forEach(([side,me,op,ix])=>{
    const ratio=me.att/Math.max(40,op.def);
    const pShot=clampA(0.125*Math.pow(ratio,1.5)*( side==="H"?1.12:0.95 ),0.03,0.26);
    if(Math.random()<pShot){
      M.shots[ix]++;
      const t=side==="H"?M.h:M.a;
      const shooter=liveScorer(side,M);
      if(Math.random()<0.42){
        M.onT[ix]++;
        const pGoal=clampA(0.26*Math.pow(ratio,1.0),0.08,0.42);
        if(Math.random()<pGoal){
          if(side==="H")M.hg++;else M.ag++;
          (side==="H"?M.sH:M.sA).push(shooter);
          const xiMe=side==="H"?M.xiH:M.xiA;
          const sIdx=xiMe.findIndex(e=>!e.off&&M.R[t][e.idx][0]===shooter);
          bumpR(M,side,sIdx,1.15);
          let aTxt="";
          if(M.ratH&&Math.random()<0.62){
            const cands=xiMe.map((e,si)=>({e,si})).filter(x=>!x.e.off&&x.si!==sIdx&&x.e.pos!=="POR");
            if(cands.length){
              const ws=cands.map(c=>M.R[t][c.e.idx][11]+M.R[t][c.e.idx][14]);
              let r=Math.random()*ws.reduce((a,b)=>a+b,0),pick=cands[0];
              for(let i=0;i<cands.length;i++){r-=ws[i];if(r<=0){pick=cands[i];break;}}
              bumpR(M,side,pick.si,0.7);
              (side==="H"?M.assH:M.assA).push(M.R[t][pick.e.idx][0]);
              aTxt=" ("+LT[LANG].assist+" "+M.R[t][pick.e.idx][0]+")";
            }
          }
          const op=side==="H"?"A":"H";
          bumpR(M,op,gkSlot(op,M),-0.25);
          const xiOp=op==="H"?M.xiH:M.xiA;
          xiOp.forEach((e,si)=>{if(!e.off&&e.pos==="DFC")bumpR(M,op,si,-0.15);});
          M.log.push(m+"' "+LT[LANG].goal(shooter,ALL[t].s,aTxt,M.hg,M.ag));
        } else if(Math.random()<0.5){
          M.log.push(m+"' "+LT[LANG].save(shooter,ALL[t].s));
          bumpR(M,side==="H"?"A":"H",gkSlot(side==="H"?"A":"H",M),0.15);
        } else bumpR(M,side==="H"?"A":"H",gkSlot(side==="H"?"A":"H",M),0.1);
      } else if(Math.random()<0.3) M.log.push(m+"' "+LT[LANG].wide(shooter,ALL[t].s));
    }
  });
  // tarjetas
  ["H","A"].forEach((side,ix)=>{
    if(Math.random()<0.019){
      const v=pickVictim(side,M,true);
      if(v){
        const t=side==="H"?M.h:M.a;
        const key=v.e.idx;
        const yel=side==="H"?M.yelCardsH:M.yelCardsA;
        if(yel[key]){
          M.red[ix]++;v.e.off=true;v.e.red=true;
          bumpR(M,side,v.si,-1.5);
          M.log.push(m+"' "+LT[LANG].red(M.R[t][key][0],ALL[t].s));
        } else {
          yel[key]=1;M.yel[ix]++;
          bumpR(M,side,v.si,-0.5);
          M.log.push(m+"' "+LT[LANG].yellow(M.R[t][key][0],ALL[t].s));
        }
      }
    }
  });
  // lesiones
  ["H","A"].forEach((side,ix)=>{
    if(Math.random()<0.0011){
      const v=pickVictim(side,M,false);
      if(v){
        const t=side==="H"?M.h:M.a;
        const weeks=1+Math.floor(Math.random()*3);
        M.inj[ix]++;v.e.off=true;
        M.newInjuries.push({t,idx:v.e.idx,weeks});
        M.log.push(m+"' "+LT[LANG].inj(M.R[t][v.e.idx][0],ALL[t].s,weeks));
        const isUser=t===myIdx;
        if(!isUser||auto)aiAutoSub(side,M,v.si);
        else {M.paused=true;M.pauseReason=LT[LANG].injPause;}
      }
    }
  });
  // cambios IA por cansancio (lado no-usuario)
  if(m===60||m===75){
    ["H","A"].forEach(side=>{
      const t=side==="H"?M.h:M.a;
      if(t===myIdx&&!auto)return;
      const xi=side==="H"?M.xiH:M.xiA, fit=side==="H"?M.fitH:M.fitA;
      let worst=-1,wFit=101;
      xi.forEach((e,si)=>{if(!e.off&&e.pos!=="POR"&&fit[si]<wFit){wFit=fit[si];worst=si;}});
      if(worst>=0&&wFit<62)aiAutoSub(side,M,worst);
    });
  }
  if(m===45){
    M.log.push(LT[LANG].ht(ALL[M.h].s,M.hg,M.ag,ALL[M.a].s));
    M.fitH.forEach((f,i)=>M.fitH[i]=Math.min(100,f+6));
    M.fitA.forEach((f,i)=>M.fitA[i]=Math.min(100,f+6));
    if(!auto){M.paused=true;M.pauseReason=LT[LANG].htPause;}
  }
  const lim=M.maxMin||90;
  if(m>=lim){
    if(M.knockout&&M.hg===M.ag&&lim===90){
      extendMatch(M);
      if(!auto){M.paused=true;M.pauseReason=LT[LANG].etPause;}
    } else if(M.knockout&&M.hg===M.ag&&lim===120){
      runShootout(M);
      M.done=true;M.paused=false;
    } else {
      M.done=true;M.paused=false;
      M.log.push(LT[LANG].ft(lim,ALL[M.h].s,M.hg,M.ag,ALL[M.a].s));
    }
  }
  return M;
}

// ============ ALARGUE Y PENALES (eliminatorias) ============
function extendMatch(M){
  M.maxMin=120;
  M.log.push(LT[LANG].et);
  M.fitH.forEach((f,i)=>M.fitH[i]=Math.min(100,f+5));
  M.fitA.forEach((f,i)=>M.fitA[i]=Math.min(100,f+5));
  M.subsH++;M.subsA++;
}
function runShootout(M){
  M.log.push(LT[LANG].pensStart);
  const takers=side=>{
    const xi=side==="H"?M.xiH:M.xiA, t=side==="H"?M.h:M.a;
    return xi.filter(e=>!e.off).map(e=>M.R[t][e.idx]).sort((a,b)=>b[8]-a[8]);
  };
  const gkRef=side=>{
    const xi=side==="H"?M.xiA:M.xiH, t=side==="H"?M.a:M.h;
    const gk=xi.find(e=>!e.off&&e.pos==="POR");
    return gk?M.R[t][gk.idx][12]:10;
  };
  const tH=takers("H"), tA=takers("A");
  let ph=0,pa=0,i=0;
  const kick=(side,p)=>{
    const ref=gkRef(side);
    const pG=Math.max(0.55,Math.min(0.94,0.78+(p[8]-ref)*0.012+(Math.random()-0.5)*0.06));
    const goal=Math.random()<pG;
    M.log.push((goal?"\u2714 ":"\u2716 ")+p[0]+" ("+ALL[side==="H"?M.h:M.a].s+") "+(goal?LT[LANG].penG:Math.random()<0.65?LT[LANG].penS:LT[LANG].penW));
    return goal;
  };
  while(true){
    const kH=kick("H",tH[i%tH.length]); if(kH)ph++;
    const restH=Math.max(0,4-i), restA=Math.max(0,5-i)-0;
    if(i<5&&((ph>pa+restA+ (5-(i+1)) )||false)){} // simplificado: chequear tras patear ambos
    const kA=kick("A",tA[i%tA.length]); if(kA)pa++;
    i++;
    if(i>=5&&ph!==pa)break;
    if(i<5){
      const remH=5-i, remA=5-i;
      if(ph>pa+remA||pa>ph+remH)break;
    }
    if(i>=20)break;
  }
  M.penH=ph;M.penA=pa;
  if(ph===pa){if(Math.random()<0.5)M.penH++;else M.penA++;}
  M.log.push(LT[LANG].penRes(ALL[M.h].s,M.penH,M.penA,ALL[M.a].s));
  M.log.push(LT[LANG].adv(tnOf(M.penH>M.penA?M.h:M.a).toUpperCase()));
}
// Sim instantanea de eliminatoria IA vs IA
function simKO(h,a,R,inj){
  const xiH=bestXI(h,"4-4-2",R,inj), xiA=bestXI(a,"4-4-2",R,inj);
  const r=simScore(h,a,xiH,xiA,R);
  let pens=null;
  if(r.hg===r.ag){
    const eh=poisson(0.35), ea=poisson(0.3);
    r.hg+=eh;r.ag+=ea;
    if(eh)for(let k=0;k<eh;k++)r.sH.push(weightedScorer(h,xiH,R));
    if(ea)for(let k=0;k<ea;k++)r.sA.push(weightedScorer(a,xiA,R));
    if(r.hg===r.ag){
      const sh=strengthOf(h,xiH,R), sa=strengthOf(a,xiA,R);
      const pH=Math.random()<(sh.att+sh.def)/(sh.att+sh.def+sa.att+sa.def)?1:0;
      pens=pH?[Math.random()<0.5?4:5,3]:[3,Math.random()<0.5?4:5];
    }
  }
  return {...r,pens,winner:pens?(pens[0]>pens[1]?h:a):(r.hg>r.ag?h:a)};
}


